ee:message.ee:set-payload:
#[output application/json --- {
          SearchTerm: "",
          IncludeInactiveRecords: false,
          Offset: 0,
          Limit: p('carestack.patient.search.limit') as Number
        }]

#[
%dw 2.0
output application/json

// CareStack gender values → FHIR gender codes
var genderMap = {
  "Male": "male",
  "Female": "female",
  "Other": "other"
}

var patients = payload.Results default payload default []
---
{
  resourceType: "Bundle",
  "type": "searchset",
  total: sizeOf(patients),
  entry: patients map (p) -> {
    resource: {
      resourceType: "Patient",
      id: p.PatientId as String,
      identifier: [{
        "type": { coding: [{ system: "http://terminology.hl7.org/CodeSystem/v2-0203", code: "MR" }] },
        value: p.PatientIdentifier as String default p.PatientId as String
      }],
      name: [{
        family: p.LastName default "Unknown",
        given: [p.FirstName default "Unknown"] ++ (if (p.MiddleName != null and p.MiddleName != "") [p.MiddleName] else [])
      }],
      gender: genderMap[p.Gender default ""] default "unknown",
      birthDate: p.DOB default null,
      address: if (p.AddressLine1 != null) [{
        line: [p.AddressLine1] ++ (if (p.AddressLine2 != null and p.AddressLine2 != "") [p.AddressLine2] else []),
        city: p.City default "Unknown",
        state: p.State default "Unknown",
        postalCode: p.ZipCode default ""
      }] else [],
      telecom: (
        (if (p.PhoneWithExt != null and p.PhoneWithExt != "") [{ system: "phone", value: p.PhoneWithExt, use: "home" }] else [])
        ++ (if (p.Email != null and p.Email != "") [{ system: "email", value: p.Email }] else [])
      ),
      active: p.IsActive default true
    }
  }
}
]

#[
%dw 2.0
output application/json

var patientId = attributes.uriParams.patientId
var chart = payload default {}
var conditions = chart.Conditions default []
---
{
  resourceType: "Bundle",
  "type": "searchset",
  total: sizeOf(conditions),
  entry: conditions map (c, idx) -> {
    resource: {
      resourceType: "Condition",
      id: patientId ++ "-cond-" ++ (idx as String),
      subject: { reference: "Patient/" ++ patientId },
      code: {
        coding: [{
          system: "http://snomed.info/sct",
          code: c.ConditionCode default "unknown",
          display: c.Description default c.Name default "Dental condition"
        }],
        text: c.Description default c.Name default "Dental condition"
      },
      clinicalStatus: {
        coding: [{ system: "http://terminology.hl7.org/CodeSystem/condition-clinical", code: "active" }]
      },
      category: [{
        coding: [{ system: "http://terminology.hl7.org/CodeSystem/condition-category", code: "encounter-diagnosis" }],
        text: "Dental"
      }]
    }
  }
}
]

#[
%dw 2.0
output application/json

var patientId = attributes.uriParams.patientId
var chart = payload default {}
var teeth = chart.Teeth default []
---
{
  resourceType: "Bundle",
  "type": "searchset",
  total: sizeOf(teeth),
  entry: teeth map (tooth, idx) -> {
    resource: {
      resourceType: "Observation",
      id: patientId ++ "-obs-" ++ (idx as String),
      status: "final",
      category: [{
        coding: [{ system: "http://terminology.hl7.org/CodeSystem/observation-category", code: "exam", display: "Exam" }]
      }],
      code: {
        coding: [{ system: "http://loinc.org", code: "34552-0", display: "Periodontal assessment" }],
        text: "Periodontal charting — Tooth " ++ (tooth.ToothNumber default tooth.Tooth default "?")
      },
      subject: { reference: "Patient/" ++ patientId },
      valueString: "Tooth " ++ (tooth.ToothNumber default tooth.Tooth default "?")
        ++ (if (tooth.PocketDepth != null) " PD:" ++ (tooth.PocketDepth as String) else "")
        ++ (if (tooth.Recession != null) " Rec:" ++ (tooth.Recession as String) else "")
        ++ (if (tooth.Mobility != null) " Mob:" ++ (tooth.Mobility as String) else "")
    }
  }
}
]

#[
%dw 2.0
output application/json

var patientId = attributes.uriParams.patientId
var procedures = (payload.Results default []) filter ($.PatientId as String == patientId)
---
{
  resourceType: "Bundle",
  "type": "searchset",
  total: sizeOf(procedures),
  entry: procedures map (proc) -> {
    resource: {
      resourceType: "MedicationRequest",
      id: proc.Id as String default "unknown",
      status: if (proc.StatusId == "Completed") "completed"
              else if (proc.StatusId == "Planned") "active"
              else "unknown",
      intent: "order",
      subject: { reference: "Patient/" ++ patientId },
      medicationCodeableConcept: {
        coding: [{
          system: "http://www.ada.org/cdt",
          code: proc.ProcedureCodeId as String default "unknown",
          display: "Dental procedure " ++ (proc.ProcedureCodeId as String default "?")
        }],
        text: "Dental procedure " ++ (proc.ProcedureCodeId as String default "?")
      },
      authoredOn: proc.DateOfService default proc.ProposedDate default null
    }
  }
}
]

#[output application/json --- {
          resourceType: "CapabilityStatement",
          status: "active",
          kind: "instance",
          software: {
            name: "CareStack Dental PMS (via MuleSoft FHIR Adapter)",
            version: "1.0.0"
          },
          fhirVersion: "4.0.1",
          format: ["json"],
          rest: [{
            mode: "server",
            resource: [
              { "type": "Patient", interaction: [{ code: "read" }, { code: "search-type" }] },
              { "type": "Condition", interaction: [{ code: "search-type" }] },
              { "type": "Observation", interaction: [{ code: "search-type" }] },
              { "type": "MedicationRequest", interaction: [{ code: "search-type" }] }
            ]
          }],
          description: "FHIR R4 adapter for CareStack Dental Practice Management System. Translates CareStack proprietary REST API (49 endpoints, 92 schemas) into FHIR-compatible responses. Auth: 3-header API key (VendorKey, AccountKey, AccountId). Native endpoints: Patient search, appointments, treatments, periodontal charting, insurance (Member/MembershipPlan/PlanSubscription), payments, procedure codes."
        }]

#[output application/json --- {
            resourceType: "OperationOutcome",
            issue: [{
              severity: "error",
              code: "exception",
              diagnostics: "CareStack REST API unreachable: " ++ (error.description default "Connection failed")
            }]
          }]

#[output application/json --- {
            resourceType: "OperationOutcome",
            issue: [{
              severity: "error",
              code: "security",
              diagnostics: "CareStack API authentication failed. Check VendorKey, AccountKey, and AccountId properties."
            }]
          }]

#[output application/json --- {
            resourceType: "OperationOutcome",
            issue: [{
              severity: "error",
              code: "exception",
              diagnostics: error.description default "An unexpected error occurred"
            }]
          }]
